const row = $input.first().json[0];
if (!row) throw new Error('Post not found in content_queue');

const script = row.youtube_script || '';

// Extract spoken lines from the structured HOOK/POINT1.../CTA format
const spoken = [];
const sections = ['HOOK', 'POINT1', 'POINT2', 'POINT3', 'CTA'];
for (const label of sections) {
  const m = script.match(new RegExp(`${label}\\s*\\([^)]*\\):\\s*\\[?([^\\[\\]\\n]+)`, 'i'));
  if (m) spoken.push(m[1].trim().replace(/[\[\]]/g, ''));
}

// Fallback: strip all labels, use raw text
const scriptText = spoken.length >= 3
  ? spoken.join(' ')
  : script
      .replace(/^(HOOK|POINT[123]|CTA)\s*\([^)]+\):\s*/gim, '')
      .replace(/[\[\]]/g, '')
      .replace(/\n{2,}/g, ' ')
      .trim();

const slides = Array.isArray(row.carousel_slides) ? row.carousel_slides : [];
if (slides.length === 0) throw new Error('carousel_slides is empty — cannot build video without slide content');

console.log(`[VideoGen] Post ${row.id} | ${slides.length} slides | script ${scriptText.length} chars`);

return [{
  json: {
    post_id:      row.id,
    idea_title:   row.idea_title || 'Untitled',
    script_text:  scriptText.substring(0, 2500),
    slides:       slides,
    image_prompt: row.image_prompt || 'Dark navy background, teal and purple accents, modern SaaS aesthetic, bold white text',
  }
}];

