const parsed  = $('Code: Parse Script + Extract Slides').first().json;
const postId  = parsed.post_id;
const slides  = parsed.slides;
const imgPr   = parsed.image_prompt;

const audioUrl = `${$env.SUPABASE_URL}/storage/v1/object/public/content-audio/shorts/${postId}.mp3`;

console.log(`[VideoGen] Audio ready: ${audioUrl} | Building ${slides.length} slide image prompts`);

return slides.map((slideText, i) => ({
  json: {
    post_id:      postId,
    idea_title:   parsed.idea_title,
    slide_index:  i,
    slide_text:   slideText,
    total_slides: slides.length,
    audio_url:    audioUrl,
    image_prompt: `${imgPr}. This slide displays the text: "${slideText}". Make the text LARGE and legible as a prominent overlay. Vertical 9:16 format. No people. Clean infographic layout.`.substring(0, 900),
  }
}));

