const dalleResponse = $input.first().json;
const imageUrl = dalleResponse.data?.[0]?.url || '';

if (!imageUrl) {
  console.error('[VideoGen] DALL-E returned no URL:', JSON.stringify(dalleResponse).substring(0, 200));
  throw new Error('DALL-E 3 returned no image URL — check OPENAI_API_KEY and billing');
}

const slide = $('Process Slides Loop').first().json;
console.log(`[VideoGen] Slide ${slide.slide_index + 1}/${slide.total_slides} image ready`);

return [{
  json: {
    post_id:      slide.post_id,
    idea_title:   slide.idea_title,
    slide_index:  slide.slide_index,
    slide_text:   slide.slide_text,
    total_slides: slide.total_slides,
    audio_url:    slide.audio_url,
    image_url:    imageUrl,
  }
}];

// Collect all processed slide items in slide order
const allSlides = $('Code: Extract Image URL').all();
if (allSlides.length === 0) throw new Error('No image URLs collected — DALL-E loop produced no output');

const sorted     = allSlides.map(i => i.json).sort((a, b) => a.slide_index - b.slide_index);
const imageUrls  = sorted.map(s => s.image_url);
const slideTexts = sorted.map(s => s.slide_text);
const first      = sorted[0];

const totalDuration = 75; // seconds
const slideDuration = totalDuration / imageUrls.length; // 15s each for 5 slides

// ─── Build Shotstack timeline ────────────────────────────────────────────────
// Track 0: Background images with Ken Burns zoom
const imageClips = imageUrls.map((url, i) => ({
  asset: { type: 'image', src: url },
  start:      parseFloat((i * slideDuration).toFixed(2)),
  length:     slideDuration,
  effect:     'zoomIn',
  transition: { in: 'fade', out: 'fade' }
}));

// Track 1: Bottom-third text overlays (HTML clip for full style control)
const textClips = slideTexts.map((text, i) => ({
  asset: {
    type:   'html',
    html:   `<p>${text.replace(/'/g, "&#39;").replace(/"/g, '&quot;')}</p>`,
    css:    'p { font-family: Arial Black, Arial, sans-serif; font-size: 52px; font-weight: 900; color: #ffffff; text-align: center; line-height: 1.3; margin: 0; padding: 20px 32px; background: rgba(0,0,0,0.68); border-radius: 12px; }',
    width:  960,
    height: 320
  },
  start:    parseFloat((i * slideDuration).toFixed(2)),
  length:   slideDuration,
  position: 'bottom',
  offset:   { x: 0, y: 0.12 },
  transition: { in: 'fade' }
}));

// Track 2: SNG Advisors branding pill (top-left, full duration)
const brandingClip = [{
  asset: {
    type:   'html',
    html:   '<div>SNG Advisors</div>',
    css:    'div { font-family: Arial, sans-serif; font-size: 36px; font-weight: 800; color: #ffffff; background: rgba(13,148,136,0.85); padding: 12px 28px; border-radius: 100px; white-space: nowrap; }',
    width:  500,
    height: 80
  },
  start:    0,
  length:   totalDuration,
  position: 'topLeft',
  offset:   { x: 0.04, y: 0.04 }
}];

const shotstack_payload = {
  timeline: {
    soundtrack: {
      src:    first.audio_url,
      effect: 'fadeOut',
      volume: 1
    },
    tracks: [
      { clips: brandingClip },
      { clips: textClips },
      { clips: imageClips }
    ]
  },
  output: {
    format:    'mp4',
    size:      { width: 1080, height: 1920 },
    fps:       30,
    quality:   'high'
  }
};

console.log(`[VideoGen] Shotstack payload built: ${imageUrls.length} slides, ${totalDuration}s`);

return [{
  json: {
    post_id:           first.post_id,
    idea_title:        first.idea_title,
    audio_url:         first.audio_url,
    image_urls:        imageUrls,
    slide_texts:       slideTexts,
    shotstack_payload: shotstack_payload
  }
}];

const res = $input.first().json;

// Shotstack success response: { success: true, message: '...', response: { id: '...', message: 'Queued' } }
const renderId = res?.response?.id || res?.data?.id || '';

if (!renderId) {
  console.error('[VideoGen] Shotstack response:', JSON.stringify(res).substring(0, 300));
  throw new Error('Shotstack did not return a render ID — check SHOTSTACK_API_KEY and account status');
}

console.log(`[VideoGen] Shotstack render queued: ${renderId}`);

const prev = $('Code: Assemble Shotstack Timeline').first().json;

return [{
  json: {
    render_id:  renderId,
    post_id:    prev.post_id,
    idea_title: prev.idea_title,
    audio_url:  prev.audio_url,
    image_urls: prev.image_urls,
  }
}];

const renderStatus = $input.first().json;

// Shotstack success response: { success: true, message: '...', response: { id, status, url, ... } }
const status   = renderStatus?.response?.status || 'unknown';
const videoUrl = renderStatus?.response?.url    || '';

if (!videoUrl || status !== 'done') {
  const errDetail = renderStatus?.response?.error || renderStatus?.message || 'no error detail';
  console.error(`[VideoGen] Render status: ${status}. Response:`, JSON.stringify(renderStatus).substring(0, 300));
  throw new Error(`Shotstack render did not produce a video URL (status: ${status}, detail: ${errDetail}). Check shotstack.io Dashboard → Renders.`);
}

const meta = $('Code: Store Render ID').first().json;
console.log(`[VideoGen] ✅ Video ready: ${videoUrl}`);

return [{
  json: {
    post_id:       meta.post_id,
    idea_title:    meta.idea_title,
    video_url:     videoUrl,
    audio_url:     meta.audio_url,
    image_urls:    meta.image_urls,
    render_id:     meta.render_id,
    render_status: status,
  }
}];

